var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……인정해 드리죠. 루나의 태업이 예상 이상으로 기력을 소진하게 했군요.","JPN":"……認めましょう。ルナのサボタージュで予想以上に力を消耗させられました。","ENG":"I'll admit that Luna's sabotage caused me to expend more energy than expected.","TWN":"……我承認，露娜的怠工消耗了比我預想得更多的體力。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님, 불러들인 침식체들도 어째서인지 오지 않는 걸요.","JPN":"マエストロ、呼び寄せた侵食体もなぜか来ません。","ENG":"Chief Conductor, the C.O.s are not responding to our summons.","TWN":"指揮家，召喚的那些侵蝕體不知道為什麼也沒有來。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흐음, 곤란한걸. 이러면 루나를 데려오는 편이 나았겠는데.","JPN":"ふーん、困ったわね。これじゃあ、ルナを連れてきた方がよかったかも。","ENG":"Hmm, that's not good. Now, it seems as if it would've been better to bring Luna here instead.","TWN":"嗯，這下麻煩了。早知道這樣，還不如把露娜帶過來了。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"부상자들은 후방으로! 탄환을 아끼지 마!","JPN":"怪我人は後方に！　弾丸を惜しむな！","ENG":"Send the wounded to the back! Don't spare any bullets!","TWN":"傷患退後！不要吝嗇彈藥！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 학회원들도 가세하기 시작했습니다.","JPN":"副戦隊長、学会員も加勢しはじめました。","ENG":"Deputy Commander, the Society members have started to fight back!","TWN":"副隊長，學會成員也開始加入了。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"전투가 길어질수록 불리한 건 우리 쪽이긴 하지.","JPN":"戦闘が長引くほど不利になるのは俺たちの方だ。","ENG":"We are only digging our own graves by prolonging this fight.","TWN":"戰鬥時間拖得越長，對我們越不利。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제일 강한 전력은 시간에 제약이 있으니 말이야.","JPN":"最強の戦力は時間に制限があるからな。","ENG":"Our strongest weapon can only operate for a limited time.","TWN":"因為最強大的戰鬥力有時間限制。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 아껴 두고 있지 않습니까.","JPN":"だから、温存しているのではないですか。","ENG":"That's why I'm saving it for later.","TWN":"所以才一直保留著不是嗎。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"안 보이는 주제에 이리저리 잘만 피해대는 침식체입니다. 발을 묶기 전까지 투자는 리스크가 크죠.","JPN":"目が見えないくせに、あちこち上手く逃げ回る侵食体です。足止めをする以前の投資はリスクが大きすぎます。","ENG":"This C.O. is blind, but she's able to avoid all of our attacks. We can't risk it until we corner her.","TWN":"她可是個明明看不見，卻總能成功躲避的侵蝕體。在困住她的手腳之前，投資的風險很大。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"공기가 바뀌었다.","JPN":"空気が変わった。","ENG":"The air changed.","TWN":"空氣變了。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"공기……?","JPN":"空気……？","ENG":"The air...?","TWN":"空氣……？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇군요. 냉각기를 가동하지 않아도 될 만큼 기온이 감소했습니다.","JPN":"本当ですね。冷却器を使わなくてもいいほどに気温が低下しています。","ENG":"I see. The temperature has fallen enough so that I don't have to activate my cooling devices.","TWN":"是啊。氣溫下降了很多，都不用開冷氣了。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"갑자기 눈이 내리네. 침식 현상 탓인가?","JPN":"いきなり雪が降ってきたわね。侵食現象のせいかしら。","ENG":"It's snowing all of a sudden. Is this due to the Counterside Effect?","TWN":"突然下雪了呢，是因為侵蝕現象嗎？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……아뇨. 귀빈께서 오셨습니다.","JPN":"……いいえ。貴賓がお越しになりました。","ENG":"...No. Our VIP has arrived.","TWN":"……不，是有貴賓來了。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"과연 왕께서 집착하시기에 부족함이 없는 자질이군요.","JPN":"なるほど、王様が執着するに足る資質です。","ENG":"Indeed, she is a worthy talent of our lord's obsession.","TWN":"果然是值得王執著的資質。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이 힘……. 그것도 순수한 인간의 몸으로. 경이로워요.","JPN":"この力……それも純粋な人間の身体で。驚異的です。","ENG":"This strength... from a mere human. Astounding.","TWN":"這股力量……還是以純粹的人類之軀，真是令人驚歎。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"결과가 어떻든, 의식은 곧 완성되겠군요.","JPN":"結果はどうであれ、もうすぐ儀式は完成されますね。","ENG":"No matter the results, the ritual will soon be complete.","TWN":"無論結果如何，儀式就快完成了。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};